{"content": "     1|import { NextRequest, NextResponse } from 'next/server'
     2|import { createClient } from '@/lib/supabase/server'
     3|
     4|export async function POST(req: NextRequest) {
     5|  try {
     6|    const supabase = await createClient()
     7|    const { data: { session } } = await supabase.auth.getSession()
     8|
     9|    const body = await req.json()
    10|    const { action } = body
    11|
    12|    if (action === 'me') {
    13|      if (!session) return NextResponse.json({ ok: false, error: 'No hay sesión' }, { status: 401 })
    14|      const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single()
    15|      return NextResponse.json({
    16|        ok: true,
    17|        user: {
    18|          id: session.user.id,
    19|          name: profile?.name || session.user.email?.split('@')[0] || '',
    20|          email: session.user.email,
    21|          phone: profile?.phone || '',
    22|          role: profile?.role || 'customer',
    23|          createdAt: profile?.created_at || session.user.created_at,
    24|        },
    25|      })
    26|    }
    27|
    28|    if (action === 'login') {
    29|      const { email, password } = body
    30|      const { error } = await supabase.auth.signInWithPassword({ email, password })
    31|      if (error) return NextResponse.json({ ok: false, error: 'Credenciales incorrectas' }, { status: 401 })
    32|      // Force refresh session to ensure cookies are set
    33|      await supabase.auth.getSession()
    34|      return NextResponse.json({ ok: true })
    35|    }
    36|
    37|    if (action === 'register') {
    38|      const { name, email, password, phone } = body
    39|      const { error } = await supabase.auth.signUp({ email, password, options: { data: { name, phone } } })
    40|      if (error) {
    41|        if (error.message.includes('already registered')) return NextResponse.json({ ok: false, error: 'Email ya registrado' }, { status: 409 })
    42|        return NextResponse.json({ ok: false, error: error.message }, { status: 400 })
    43|      }
    44|      return NextResponse.json({ ok: true })
    45|    }
    46|
    47|    if (action === 'logout') {
    48|      await supabase.auth.signOut()
    49|      return NextResponse.json({ ok: true })
    50|    }
    51|
    52|    return NextResponse.json({ error: 'Acción desconocida' }, { status: 400 })
    53|  } catch (err) {
    54|    return NextResponse.json({ error: String(err) }, { status: 500 })
    55|  }
